var restrictedOptions = new JsonSerializerOptions();
restrictedOptions.TypeInfoResolver = SmallContext.Default;

if (restrictedOptions.TryGetTypeInfo<UnknownType>(out JsonTypeInfo<UnknownType>? missing))
{
    Console.WriteLine($"Unexpected: resolved {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownType> returned false — no metadata available.");
}

// Types
public record Person(string Name, int Age);
public record UnknownType(string Value);

// A source-gen context that only resolves Person
[JsonSerializable(typeof(Person))]
public partial class SmallContext : JsonSerializerContext;
EOF

